patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..3c5d3a4823ea 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -9425,6 +9425,23 @@ isImpliedCondICmps(CmpPredicate LPred, const Value *L0, const Value *L1,
       (RPred == ICmpInst::ICMP_ULT || RPred == ICmpInst::ICMP_UGE) &&
       match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))))
     return CmpPredicate::getMatching(LPred, RPred).has_value();
+  // icmp eq (sub (ptrtoint A), (ptrtoint B)), NonZero implies icmp ne A, B
+  // if NonZero is known non-zero. This is because if A == B, then
+  // ptrtoint(A) - ptrtoint(B) == 0, which would contradict NonZero != 0.
+  // Handle both direct ptrtoint and ptrtoint followed by truncation.
+  if (LPred == ICmpInst::ICMP_EQ && RPred == ICmpInst::ICMP_NE &&
+      R0->getType()->isPointerTy() && R1->getType()->isPointerTy()) {
+    // Match sub(ptrtoint(A), ptrtoint(B)) or sub(trunc(ptrtoint(A)), trunc(ptrtoint(B)))
+    Value *PTIA = nullptr, *PTIB = nullptr;
+    if ((match(L0, m_Sub(m_PtrToInt(m_Value(PTIA)), m_PtrToInt(m_Value(PTIB)))) ||
+         match(L0, m_Sub(m_Trunc(m_PtrToInt(m_Value(PTIA))),
+                         m_Trunc(m_PtrToInt(m_Value(PTIB)))))) &&
+        PTIA == R0 && PTIB == R1) {
+      KnownBits Known = computeKnownBits(L1, DL);
+      if (Known.isNonZero())
+        return true;
+    }
+  }

   if (auto P = CmpPredicate::getMatching(LPred, RPred))
     return isImpliedCondOperands(*P, L0, L1, R0, R1);

